import 'dart:async';
import 'dart:convert';

import '../lib/chunk_text_decoder.dart';
import '../lib/event_parser.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool sameList(List<String> actual, List<String> expected) {
  if (actual.length != expected.length) return false;
  for (var index = 0; index < actual.length; index++) {
    if (actual[index] != expected[index]) return false;
  }
  return true;
}

Future<void> main() async {
  final word = 'caf\u00e9';
  final encodedWord = utf8.encode(word);
  final marker = encodedWord.indexOf(0xc3);
  check(marker >= 0, 'multibyte marker');
  final decoded = await decodeByteChunks(Stream<List<int>>.fromIterable([
    encodedWord.sublist(0, marker + 1),
    encodedWord.sublist(marker + 1),
  ])).join();
  check(decoded == word, 'direct decoder preserves split text');

  final crlf = Stream<List<int>>.value(utf8.encode('data: accepted\r\n'));
  check(sameList(await parseEventData(crlf).toList(), ['accepted']), 'parser normalizes proxy lines');

  final integratedBytes = utf8.encode('data: caf\u00e9\r\n');
  final integrated = Stream<List<int>>.fromIterable([
    integratedBytes.sublist(0, integratedBytes.length - 2),
    integratedBytes.sublist(integratedBytes.length - 2),
  ]);
  check(sameList(await parseEventData(integrated).toList(), [word]), 'integrated event boundary');
}
